123→export function HomeFeedScreen({navigation}: Props) {
124→  const {user} = useAuth();
125→  const {colors} = useTheme();
126→  const [refreshing, setRefreshing] = useState(false);
127→  const [activeFilter, setActiveFilter] = useState('all');
128→
129→  const feedQuery = useInfiniteQuery({
130→    queryKey: ['feed', user?.id],
131→    queryFn: ({pageParam}) =>
132→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
133→    initialPageParam: null as string | null,
134→    getNextPageParam: lastPage => getNextCursor(lastPage),
135→  });
136→
137→  const posts = useMemo(
138→    () => feedQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
139→    [feedQuery.data?.pages],
140→  );
141→
142→  const onRefresh = async () => {
143→    setRefreshing(true);
144→    try {
145→      await feedQuery.refetch();
146→    } finally {
147→      setRefreshing(false);
148→    }
149→  };
150→
151→  const handleQuickAction = (key: string) => {
152→    if (key === 'canvas') {
153→      navigation.navigate('Canvas');
154→    } else if (key === 'freedom_wall') {
155→      navigation.navigate('FreedomWall');
156→    } else if (key === 'universe') {
157→      navigation.navigate('Universe');
158→    } else {
159→      setActiveFilter(key);
160→    }
161→  };
162→
163→  return (
164→    <SafeAreaView
165→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
166→      edges={['top']}>
167→      {/* Branded header */}
168→      <View
169→        style={[
170→          styles.header,
171→          {borderBottomColor: colors.borderCard},
172→        ]}>
173→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
174→          iskrib
175→        </Text>
176→      </View>
177→
178→      {/* Filter chips */}
179→      <View style={styles.chipRow}>
180→        <ScrollView
181→          horizontal
182→          showsHorizontalScrollIndicator={false}
183→          contentContainerStyle={styles.chipScroll}>
184→          {QUICK_ACTIONS.map(action => (
185→            <Chip
186→              key={action.key}
187→              label={action.label}
188→              active={activeFilter === action.key}
189→              onPress={() => handleQuickAction(action.key)}
190→            />
191→          ))}
192→        </ScrollView>
193→      </View>
194→
195→      {/* Feed */}
196→      <FlatList
197→        data={posts}
198→        onRefresh={onRefresh}
199→        refreshing={refreshing}
200→        onEndReachedThreshold={0.25}
201→        onEndReached={() => {
202→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
203→            feedQuery.fetchNextPage();
204→          }
205→        }}
206→        contentContainerStyle={styles.listContent}
207→        showsVerticalScrollIndicator={false}
208→        ListEmptyComponent={
209→          feedQuery.isLoading ? (
210→            <View style={styles.skeletonList}>
211→              <PostCardSkeleton />
212→              <PostCardSkeleton />
213→              <PostCardSkeleton />
214→            </View>
215→          ) : (
216→            <EmptyState
217→              title="No posts yet"
218→              subtitle="Pull to refresh or create your first journal post."
219→            />
220→          )
221→        }
222→        ListFooterComponent={
223→          feedQuery.isFetchingNextPage ? (
224→            <View style={styles.loadingMore}>
225→              <PostCardSkeleton />
226→            </View>
227→          ) : null
228→        }
229→        keyExtractor={item => item.id}
230→        renderItem={({item}) => {
231→          const preview = extractPlainText(item.content).slice(0, 180);
232→          const likeCount = resolveCount(
233→            item.like_count,
234→            item.likes_count,
235→          );
236→          const commentCount = resolveCount(
237→            item.comment_count,
238→            item.comments_count,
239→          );
240→          const bookmarkCount = resolveCount(item.bookmark_count);
241→          const bannerImage = extractBannerImage(
242→            item.content,
243→            (item as any).images,
244→          );
245→
246→          return (
247→            <PostCard
248→              title={item.title || 'Untitled Post'}
249→              bodyPreview={preview || 'No preview text available.'}
250→              authorName={item.users?.name || 'Unknown author'}
