 81→export function PostDetailScreen({route}: Props) {
 82→  const {user, session} = useAuth();
 83→  const {colors} = useTheme();
 84→  const {journalId} = route.params;
 85→  const token = session?.access_token ?? '';
 86→  const [commentInput, setCommentInput] = useState('');
 87→  const [repostCaption, setRepostCaption] = useState('');
 88→  const [showRepost, setShowRepost] = useState(false);
 89→
 90→  const detailQuery = useQuery({
 91→    queryKey: ['journal', journalId, user?.id],
 92→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
 93→  });
 94→
 95→  const commentsQuery = useQuery({
 96→    queryKey: ['journal-comments', journalId],
 97→    queryFn: () => socialApi.getComments(journalId, null, 20),
 98→  });
 99→
100→  const likeMutation = useMutation({
101→    mutationFn: async () => {
102→      const journal = detailQuery.data?.journal;
103→      const receiverId = journal?.user_id ?? journal?.users?.id;
104→      if (!token) throw new Error('Please log in to like this post.');
105→      if (!journal?.id || !receiverId) throw new Error('Missing journal data.');
106→      const metadata = session?.user.user_metadata as {name?: string; avatar_url?: string} | undefined;
107→      return socialApi.likeJournal(token, {
108→        journalId: journal.id,
109→        receiverId,
110→        sendername: metadata?.name,
111→        senderImageUrl: metadata?.avatar_url,
112→        senderEmail: session?.user.email,
113→      });
114→    },
115→    onSuccess: () => {
116→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
117→      queryClient.invalidateQueries({queryKey: ['feed']});
118→    },
119→    onError: e => Alert.alert('Like failed', e instanceof Error ? e.message : 'Error'),
120→  });
121→
122→  const bookmarkMutation = useMutation({
123→    mutationFn: async () => {
124→      if (!token) throw new Error('Please log in to bookmark.');
125→      return socialApi.toggleBookmark(token, {journalId});
126→    },
127→    onSuccess: () => {
128→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
129→      queryClient.invalidateQueries({queryKey: ['feed']});
130→    },
131→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
132→  });
133→
134→  const addCommentMutation = useMutation({
135→    mutationFn: async () => {
136→      const body = commentInput.trim();
137→      const receiverId = detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id;
138→      if (!token) throw new Error('Please log in to comment.');
139→      if (!body) throw new Error('Comment cannot be empty.');
140→      if (!receiverId) throw new Error('Missing journal owner.');
141→      return socialApi.addComment(token, {comments: body, postId: journalId, receiverId});
142→    },
143→    onSuccess: () => {
144→      setCommentInput('');
145→      queryClient.invalidateQueries({queryKey: ['journal-comments', journalId]});
146→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
147→    },
148→    onError: e => Alert.alert('Comment failed', e instanceof Error ? e.message : 'Error'),
149→  });
150→
151→  const repostMutation = useMutation({
152→    mutationFn: async () => {
153→      if (!token) throw new Error('Please log in to repost.');
154→      return socialApi.createRepost(token, {
155→        sourceJournalId: journalId,
156→        caption: repostCaption.trim() || undefined,
157→      });
158→    },
159→    onSuccess: () => {
160→      setRepostCaption('');
161→      setShowRepost(false);
162→      Alert.alert('Reposted', 'Post was reposted to your feed.');
163→      queryClient.invalidateQueries({queryKey: ['feed']});
164→    },
165→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
166→  });
167→
168→  const journal = detailQuery.data?.journal;
169→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
170→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
171→  const bookmarkCount = resolveCount(journal?.bookmark_count);
172→  const comments = commentsQuery.data?.comments ?? [];
